class ImportResult {
    private String batchId;
    private int successCount;
    private int errorCount;
    private List<String> errors;
    private List<EntityGroupResult> groupResults;
    
    public ImportResult() {
        this.errors = new ArrayList<>();
        this.groupResults = new ArrayList<>();
    }
    
    public String getBatchId() {
        return batchId;
    }
    
    public void setBatchId(String batchId) {
        this.batchId = batchId;
    }
    
    public int getSuccessCount() {
        return successCount;
    }
    
    public void incrementSuccessCount() {
        this.successCount++;
    }
    
    public int getErrorCount() {
        return errorCount;
    }
    
    public void incrementErrorCount() {
        this.errorCount++;
    }
    
    public List<String> getErrors() {
        return errors;
    }
    
    public void addError(String error) {
        this.errors.add(error);
    }
    
    public void addGroupResult(EntityGroupResult groupResult) {
        this.groupResults.add(groupResult);
        this.successCount += groupResult.getSuccessCount();
        this.errorCount += groupResult.getErrorCount();
        this.errors.addAll(groupResult.getErrors());
    }
}

