class DataProcessor {
    private static final Logger logger = Logger.getLogger(DataProcessor.class.getName());
    private Connection connection;
    private Map<String, ImportStatus> statusMap;
    
    public DataProcessor() {
        this.statusMap = new HashMap<>();
        initializeDatabase();
    }
    
    private void initializeDatabase() {
        try {
            String url = "jdbc:h2:mem:enterprisedb;DB_CLOSE_DELAY=-1";
            connection = DriverManager.getConnection(url, "sa", "");
            
            try (PreparedStatement stmt = connection.prepareStatement(
                "CREATE TABLE IF NOT EXISTS entities (" +
                "id VARCHAR(255) PRIMARY KEY, " +
                "type VARCHAR(100), " +
                "data TEXT, " +
                "created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP)")) {
                stmt.execute();
            }
            
        } catch (SQLException e) {
            logger.severe("Failed to initialize database: " + e.getMessage());
        }
    }
    
    public void saveEntity(EntityData entityData) throws SQLException {
        String sql = "INSERT INTO entities (id, type, data) VALUES (?, ?, ?)";
        
        try (PreparedStatement stmt = connection.prepareStatement(sql)) {
            stmt.setString(1, entityData.getId());
            stmt.setString(2, entityData.getType());
            stmt.setString(3, entityData.getAttributes().toString());
            stmt.executeUpdate();
        }
    }
    
    public ImportStatus getImportStatus(String batchId) {
        return statusMap.getOrDefault(batchId, 
            new ImportStatus(batchId, "UNKNOWN", 0));
    }
    
    public void updateStatus(String batchId, String status, int progress) {
        statusMap.put(batchId, new ImportStatus(batchId, status, progress));
    }
    
    public void close() {
        try {
            if (connection != null && !connection.isClosed()) {
                connection.close();
            }
        } catch (SQLException e) {
            logger.severe("Error closing database connection: " + e.getMessage());
        }
    }
}

